#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define FLT_MAX 3.40282347e+38f

inline float euclid_dist_2(__global float *pt1,
                    __global float *pt2,
                    int    numdims)
{
    float ans=0.0f;
    for (int i=0; i<numdims; i++)
        ans += (pt1[i]-pt2[i]) * (pt1[i]-pt2[i]);
    return ans;
}

inline int find_nearest_point(__global float  *pt,          
                       int     nfeatures,
                       __global float **pts,         
                       int     npts)
{
    int index = 0;
    float min_dist=FLT_MAX;

    for (int i=0; i<npts; i++) {
        float dist;
        dist = euclid_dist_2(pt, pts[i], nfeatures);  
        if (dist < min_dist) {
            min_dist = dist;
            index    = i;
        }
    }
    return index;
}

__kernel void kmeans_assign_clusters(
    __global float *features,       // flattened features array: npoints * nfeatures
    __global float *clusters,       // flattened clusters array: nclusters * nfeatures
    __global int *membership,       // membership array: npoints
    __global float *partial_new_centers, // partial sums: nthreads * nclusters * nfeatures
    __global int *partial_new_centers_len, // partial counts: nthreads * nclusters
    int npoints,
    int nfeatures,
    int nclusters)
{
    int gid = get_global_id(0);
    int tid = get_local_id(0);
    int local_size = get_local_size(0);
    int group_id = get_group_id(0);

    if (gid >= npoints) return;

    // Compute pointer to feature vector for this point
    __global float *pt = &features[gid * nfeatures];

    // Find nearest cluster
    int index = 0;
    float min_dist = FLT_MAX;
    for (int i=0; i<nclusters; i++) {
        __global float *cluster_pt = &clusters[i * nfeatures];
        float dist = 0.0f;
        for (int d=0; d<nfeatures; d++) {
            float diff = pt[d] - cluster_pt[d];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }

    // Update membership
    int old_membership = membership[gid];
    membership[gid] = index;

    // Atomically update partial sums and counts
    int thread_id = group_id * local_size + tid;
    int base_len_idx = thread_id * nclusters + index;
    int base_center_idx = (thread_id * nclusters + index) * nfeatures;

    atomic_inc(&partial_new_centers_len[base_len_idx]);
    for (int d=0; d<nfeatures; d++) {
        // Use atomic add for floats if supported, else use atomic operations on ints
        // Here we assume atomic_add for float is supported (OpenCL 2.0+)
        atomic_add(&partial_new_centers[base_center_idx + d], pt[d]);
    }
}

__kernel void kmeans_update_clusters(
    __global float *clusters,       // clusters array: nclusters * nfeatures
    __global float *partial_new_centers, // partial sums: nthreads * nclusters * nfeatures
    __global int *partial_new_centers_len, // partial counts: nthreads * nclusters
    __global float *new_centers,    // output new centers: nclusters * nfeatures
    __global int *new_centers_len,  // output counts: nclusters
    int nthreads,
    int nclusters,
    int nfeatures)
{
    int gid = get_global_id(0);
    if (gid >= nclusters) return;

    // Initialize sums and counts
    float sum_features[128]; // max features assumed 128, adjust if needed
    for (int d=0; d<nfeatures; d++)
        sum_features[d] = 0.0f;
    int count = 0;

    // Sum over threads
    for (int t=0; t<nthreads; t++) {
        int len_idx = t * nclusters + gid;
        count += partial_new_centers_len[len_idx];
        int center_idx = (t * nclusters + gid) * nfeatures;
        for (int d=0; d<nfeatures; d++) {
            sum_features[d] += partial_new_centers[center_idx + d];
        }
    }

    // Store sums and counts
    new_centers_len[gid] = count;
    for (int d=0; d<nfeatures; d++) {
        new_centers[gid * nfeatures + d] = sum_features[d];
    }
}

__kernel void kmeans_finalize_clusters(
    __global float *clusters,       // clusters array: nclusters * nfeatures
    __global float *new_centers,    // new centers sums: nclusters * nfeatures
    __global int *new_centers_len,  // counts: nclusters
    int nclusters,
    int nfeatures)
{
    int gid = get_global_id(0);
    if (gid >= nclusters) return;

    int count = new_centers_len[gid];
    if (count > 0) {
        for (int d=0; d<nfeatures; d++) {
            clusters[gid * nfeatures + d] = new_centers[gid * nfeatures + d] / count;
        }
    }
}

__kernel void kmeans_reset_partial(
    __global float *partial_new_centers,
    __global int *partial_new_centers_len,
    int nthreads,
    int nclusters,
    int nfeatures)
{
    int gid = get_global_id(0);
    int total_centers = nthreads * nclusters;
    if (gid >= total_centers) return;

    partial_new_centers_len[gid] = 0;
    for (int d=0; d<nfeatures; d++) {
        partial_new_centers[gid * nfeatures + d] = 0.0f;
    }
}
